/*
 * Korg prologue parameter table — single source of truth for every program
 * parameter of the prologue definition (both variants: prologue-8 and
 * prologue-16 programs are format-identical, spec §14). Ids are stable and
 * append-only; raw ranges mirror the hardware (docs/prologue-spec.md §2,
 * MIDIimp TABLE 3).
 *
 * Layout — the prologue is BITIMBRAL (spec §2): program-global params first
 * (ids 0..GLOBAL_PARAM_COUNT-1, stored once per program), then two identical
 * per-timbre blocks generated by the timbreDefs factory (TIMBRE 1 = MAIN,
 * TIMBRE 2 = SUB). Timbre params get keys 't1'/'t2' + capitalized base key
 * ('t1Vco1Wave') and labels 'T1 '/'T2 ' + base label ('T1 VCO1 WAVE').
 * Engine/panel/CC code addresses timbre params through TIMBRE_BLOCKS
 * (semantic name -> param id per timbre) — never through key-string math.
 * Three replica-only params (RP: L.F. COMP ON/GAIN + VOICE CAP, documented
 * deviations) are appended after the timbre blocks.
 *
 * Name-level fields (program name) live outside params as usual; TEMPO lives
 * in Program.seq.bpm (spec §15 — one transport tempo, the arp reads it).
 * CATEGORY/FREQUENT/LIKE sort metadata and the USER ENGINE PARAM1-6 slots
 * are out of scope (implementation-notes.md: user slots ship built-ins).
 *
 * Motion recordability: the prologue has NO step sequencer and NO motion
 * sequencing (spec §10) — every param is motion: false; MOTION_PARAM_IDS
 * carries only the two virtual targets and the StepSeq stays dormant.
 *
 * Factory init defaults are UNCONFIRMED (no hardware program dump available);
 * values below are the replica's musically-neutral init, mirroring the
 * family tables.
 */
import {
  type ParamMeta,
  type MotionTargetMeta,
  knob,
  sw,
  menu,
  buildParamTable,
  clampParamIn,
  formatParamIn,
  motionParamIdsOf,
  motionParamLabelIn,
  motionMetaFor,
} from '../../shared/paramdef'
import { fmtSec, fmtHz, fmtDb } from '../../shared/maps'
import * as curves from './curves'
import {
  MODFX_TYPES,
  CHORUS_SUBS,
  ENSEMBLE_SUBS,
  PHASER_SUBS,
  FLANGER_SUBS,
  USER_MODFX_SUBS,
  DELAY_SUBS,
  REVERB_SUBS,
  ARP_TYPES,
  ARP_RATES,
  WHEEL_ASSIGN_DESTS,
  MICRO_TUNINGS,
} from './curves'

// ---------------------------------------------------------------------------
// Program-global params (MIDIimp TABLE 3 bytes 16..79)
// ---------------------------------------------------------------------------
