  SUB_ON: 1,
  EDIT_TIMBRE: 2,
  TIMBRE_TYPE: 3,
  BALANCE: 4,
  POSITION: 5,
  SPLIT_POINT: 6,
  AMP_VELOCITY: 7,
  PORTAMENTO_MODE: 8,
  PROGRAM_LEVEL: 9,
  PROGRAM_TUNING: 10,
  PROGRAM_TRANSPOSE: 11,
  MICRO_TUNING: 12,
  SCALE_KEY: 13,
  MODFX_ON: 14,
  MODFX_TYPE: 15,
  MODFX_SUB_CHORUS: 16,
  MODFX_SUB_ENSEMBLE: 17,
  MODFX_SUB_PHASER: 18,
  MODFX_SUB_FLANGER: 19,
  MODFX_SUB_USER: 20,
  MODFX_SPEED: 21,
  MODFX_DEPTH: 22,
  MODFX_ROUTING: 23,
  DLRV_SELECT: 24,
  DELAY_SUB: 25,
  REVERB_SUB: 26,
  DLRV_TIME: 27,
  DLRV_DEPTH: 28,
  DLRV_DRYWET: 29,
  DLRV_ON: 30,
  DLRV_ROUTING: 31,
