/** Semantic timbre-param names (the TIMBRE_BLOCKS accessor surface). */
export type TimbreKey = (typeof TIMBRE_SPECS)[number]['name']

/** One timbre block's param ids, keyed by semantic name. */
export type TimbreParamIds = { readonly [K in TimbreKey]: number }

export const TIMBRE_PARAM_COUNT = TIMBRE_SPECS.length
/** Replica-only params appended AFTER the two timbre blocks (see RP below). */
export const REPLICA_PARAM_COUNT = 3
export const PARAM_COUNT = GLOBAL_PARAM_COUNT + 2 * TIMBRE_PARAM_COUNT + REPLICA_PARAM_COUNT

/** Generate one timbre block: defs (keys 't<n>' + capitalized base, labels
 *  'T<n> ' + base) plus the semantic-name -> id map, from one spec list. */
function timbreDefs(t: 1 | 2, baseId: number): { defs: ParamMeta[]; ids: TimbreParamIds } {
  const defs: ParamMeta[] = []
  const ids: Record<string, number> = {}
  for (let i = 0; i < TIMBRE_SPECS.length; i++) {
    const s = TIMBRE_SPECS[i]
    const id = baseId + i
    ids[s.name] = id
    const key = 't' + t + s.name.charAt(0).toUpperCase() + s.name.slice(1)
    defs.push(s.make(id, key, 'T' + t + ' ' + s.label))
  }
  return { defs, ids: ids as TimbreParamIds }
}

const T1 = timbreDefs(1, GLOBAL_PARAM_COUNT)
const T2 = timbreDefs(2, GLOBAL_PARAM_COUNT + TIMBRE_PARAM_COUNT)

/** Per-timbre param ids ([0] = TIMBRE 1 / MAIN, [1] = TIMBRE 2 / SUB) —
 *  engine/panel/CC code loops over timbres through this, never key strings. */
export const TIMBRE_BLOCKS: readonly [TimbreParamIds, TimbreParamIds] = [T1.ids, T2.ids]

// ---------------------------------------------------------------------------
// Replica-only params — documented DEVIATIONS from hardware program data,
// appended AFTER the two timbre blocks so the hardware-faithful ids 0..167
// never move (append-only). They serialize by key like everything else:
//   - L.F. COMP (prologue-16, spec §7): a physical panel section with zero
//     program/MIDI presence on hardware ("not stored in programs"); the
//     replica stores ON + GAIN as ordinary params — simplest and honest.
//   - VOICE CAP: pure replica config with no hardware analog — the
//     prologue-8 variant runs the same 16-voice engine capped to 8
//     (spec §14), and spec §15's low-end fallback caps further. The engine
//     never allocates voice indices >= cap; the bank stays 16 wide.
// ---------------------------------------------------------------------------
const RP_BASE = GLOBAL_PARAM_COUNT + 2 * TIMBRE_PARAM_COUNT
export const RP = {
  LF_COMP_ON: RP_BASE,
  LF_COMP_GAIN: RP_BASE + 1,
  VOICE_CAP: RP_BASE + 2,
} as const

const REPLICA_DEFS: ParamMeta[] = [
  sw(RP.LF_COMP_ON, 'lfCompOn', 'L.F. COMP', ONOFF, 0),
  // GAIN default 0 = no low boost when switched on (neutral; the hardware
  // knob's detent behavior is UNCONFIRMED — dsp/fx/lfcomp.ts voicing too).
  knob(RP.LF_COMP_GAIN, 'lfCompGain', 'L.F. COMP GAIN', 0),
  menu(RP.VOICE_CAP, 'voiceCap', 'VOICE CAP', 1, 16, 16, {
    fmt: (r) => Math.round(r) + ' VOICE',
  }),
]

// No motion sequencing on the prologue (spec §10): strip the factories'
// default motion: true from every param in one place.
const DEFS: ParamMeta[] = [...GLOBAL_DEFS, ...T1.defs, ...T2.defs, ...REPLICA_DEFS].map((m) =>
  m.motion ? { ...m, motion: false } : m
)

export const PARAMS: readonly ParamMeta[] = buildParamTable(DEFS, PARAM_COUNT)

export const PARAM_BY_KEY: ReadonlyMap<string, ParamMeta> = new Map(PARAMS.map((p) => [p.key, p]))

export function clampParam(id: number, v: number): number {
  return clampParamIn(PARAMS, id, v)
}

export function formatParam(id: number, v: number): string {
  return formatParamIn(PARAMS, id, v)
}

/** Motion targets: no program params (spec §10 — no motion sequencing), only
 *  the two virtual ids remain; the StepSeq stays constructed-but-dormant. */
export const MOTION_PARAM_IDS: readonly number[] = motionParamIdsOf(PARAMS)

export function motionParamLabel(id: number): string {
  return motionParamLabelIn(PARAMS, id)
}

/** Motion-target predicates for the StepSeq core, bound to this table. */
export const MOTION_META: MotionTargetMeta = motionMetaFor(PARAMS)

// ---------------------------------------------------------------------------
// M.WHEEL / aftertouch destination -> param id (WHEEL_ASSIGN_DESTS order,
// curves.ts; per-timbre assign). Lives here rather than in curves.ts so
// curves stays import-free of the id tables (no cycle) — the og/mono
// sliderDestParam precedent.
// ---------------------------------------------------------------------------

/** Virtual destination: offsets the sequencer/arp gate time (the family
 *  GATE TIME layer; og SLIDER_DEST_GATE_TIME precedent). */
export const WHEEL_DEST_GATE_TIME = -2
/** Engine-dependent destination: resolves to the timbre's active MULTI
 *  TYPE's shape param (the xd JOY_DEST_IDS -2 precedent, synths/xd/engine.ts). */
export const WHEEL_DEST_MULTI_SHAPE = -3

function wheelDestIds(t: TimbreParamIds): readonly number[] {
  return [
    P.BALANCE, // BALANCE (program-global — a real param, no sentinel needed)
    t.portamento,
    t.voiceSpread,
    t.vmDepth,
    t.vco1Pitch,
    t.vco1Shape,
    t.vco2Pitch,
    t.vco2Shape,
    t.crossMod,
    t.pitchEgInt,
    WHEEL_DEST_MULTI_SHAPE, // MULTI SHAPE (per active MULTI TYPE)
    t.vco1Level,
    t.vco2Level,
    t.multiLevel,
    t.cutoff,
    t.resonance,
    t.cutoffEgInt,
    t.ampAttack,
    t.ampDecay,
    t.ampSustain,
    t.ampRelease,
    t.egAttack,
    t.egDecay,
    t.egSustain,
    t.egRelease,
    t.lfoRate,
    t.lfoInt,
    P.MODFX_SPEED, // program-global FX params
    P.MODFX_DEPTH,
    P.DLRV_TIME,
    P.DLRV_DEPTH,
    WHEEL_DEST_GATE_TIME, // GATE TIME (virtual)
  ]
}

const WHEEL_DEST_IDS: readonly (readonly number[])[] = [wheelDestIds(T1.ids), wheelDestIds(T2.ids)]

/** Param id for a wheel/aftertouch destination index 0..31 on a timbre
 *  (0 = MAIN, 1 = SUB); negative = virtual/engine-dependent
 *  (WHEEL_DEST_GATE_TIME / WHEEL_DEST_MULTI_SHAPE). */
export function wheelDestParam(destIndex: number, timbre: number): number {
  const t = WHEEL_DEST_IDS[timbre >= 1 ? 1 : 0]
  const i = Math.max(0, Math.min(t.length - 1, Math.round(destIndex)))
  return t[i]
}
